import { Navigate, useLocation } from "react-router-dom";
import { useEffect, useState } from "react";

export default function ProtectedRoute({ children, allowedRoles = [] }) {
  const [isAuthenticated, setIsAuthenticated] = useState(null);
  const [userRole, setUserRole] = useState(null);
  const location = useLocation();

  useEffect(() => {
    // Check authentication status
    const token = localStorage.getItem("access_token");
    const role = localStorage.getItem("role");
    
    setIsAuthenticated(!!token);
    setUserRole(role);
  }, []);

  // Show loading while checking
  if (isAuthenticated === null) {
    return (
      <div style={{
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
        height: "100vh",
        background: "#0a0a0a",
        color: "#c89d5c"
      }}>
        <div className="loading-spinner">Loading...</div>
      </div>
    );
  }

  // Not authenticated - redirect to staff login (default for admin/staff)
  if (!isAuthenticated) {
    // If trying to access customer routes, redirect to customer login
    if (allowedRoles.includes("customer") || location.pathname === "/profile") {
      return <Navigate to="/login" state={{ from: location }} replace />;
    }
    return <Navigate to="/staff-login" state={{ from: location }} replace />;
  }

  // Check role authorization
  if (allowedRoles.length > 0 && !allowedRoles.includes(userRole)) {
    // User doesn't have required role - redirect to their appropriate dashboard
    if (userRole === "admin") {
      return <Navigate to="/admin" replace />;
    } else if (userRole === "staff") {
      return <Navigate to="/staff" replace />;
    } else if (userRole === "customer") {
      // Customer trying to access admin/staff routes
      return <Navigate to="/" replace />;
    } else {
      // No valid role - redirect to staff login
      return <Navigate to="/staff-login" replace />;
    }
  }

  return children;
}
